bool ok[9][9][4];
void wall(ll t,ll l,ll r){
  if(t==1){
    ok[l][r][2]=false;
    ok[l+1][r][0]=false;
    ok[l][r+1][2]=false;
    ok[l+1][r+1][0]=false;
  }
  if(t==2){
    ok[l][r][1]=false;
    ok[l][r+1][3]=false;
    ok[l+1][r][1]=false;
    ok[l+1][r+1][3]=false;
  }
}
bool ok2[9][9][4];
bool check(ll t,ll l,ll r){
  for(int i=0;i<9;i++){
    for(int j=0;j<9;j++){
      for(int k=0;k<4;k++){
        ok2[i][j][k]=ok[i][j][k];
      }
    }
  }
  if(t==1){
    if(!ok2[l][r][2]) return false;
    if(!ok2[l+1][r][0]) return false;
    if(!ok2[l][r+1][2]) return false;
    if(!ok2[l+1][r+1][0]) return false;
    ok2[l][r][1]=false;
    ok2[l][r+1][3]=false;
    ok2[l+1][r][1]=false;
    ok2[l+1][r+1][3]=false;
  }
  if(t==2){
    if(!ok2[l][r][1]) return false;
    if(!ok2[l+1][r][1]) return false;
    if(!ok2[l][r+1][3]) return false;
    if(!ok2[l+1][r+1][3]) return false;
    ok2[l][r][1]=false;
    ok2[l][r+1][3]=false;
    ok2[l+1][r][1]=false;
    ok2[l+1][r+1][3]=false;
  }
  UnionFind uf(81);
  for(int i=0;i<9;i++){
    for(int j=0;j<9;j++){
      for(int k=0;k<4;k++){
        if(ok2[i][j][k]) uf.merge(i+j*9,(i+x[k])+(j+y[k])*9);
      }
    }
  }
  return (uf.size(0)==81);
}
ll mx,my,px,py;
char g[9][9];
void Go(ll p){
  cout<<0<<" "<<p<<endl;
  cout.flush();
  mx+=x[p];
  my+=y[p];
}
void step(){
  for(int i=0;i<4;i++){
    if(ok[mx][my][i]){
      Go(i);
      return;
    }
  }
  vector<ll> sansei(4);
  vector<vector<vector<ll>>> d(4,vector<vector<ll>>(9,vector<ll>(9,inf)));
  for(int i=0;i<4;i++){
    if(ok[mx][my][i]==false) continue;
    ll ni=mx+x[i],nj=my+y[i];
    d[i][ni][nj]=0;
    queue<P> q;
    q.push({ni,nj});
    while(q.size()){
      auto v=q.front();
      q.pop();
      for(int j=0;j<4;j++){
        if(ok[v.fi][v.se][j]){
          if(chmin(d[i][v.fi+x[j]][v.se+y[j]],d[i][v.fi][v.se]+1)){
            q.push({v.fi+x[j],v.se+y[j]});
          }
        }
      }
    }
  }
  for(int i=0;i<9;i++){
    for(int j=0;j<9;j++){
      if(g[i][j]=='#'){
        ll D=inf;
        for(int k=0;k<4;k++){
          if(ok[mx][my][k]){
            chmin(D,1+d[k][i][j]);
          }
        }
        for(int k=0;k<4;k++){
          if(ok[mx][my][k]){
            if(D==1+d[k][i][j]) sansei[k]++;
          }
        }
      }
    }
  }
  vector<ll> ind;
  for(int i=0;i<4;i++){
    if(ok[mx][my][i]){
      if(g[mx+x[i]][my+y[i]]=='#') ind.pb(i);
    }
  }
  if(ind.size()==0){
    ll p=-1;
    ll c=-1;
    for(int i=0;i<4;i++){
      if(chmax(c,sansei[i])) p=i;
    }
    Go(p);
  }
  else{
    ll p=-1,c=-1;
    for(int i=0;i<ind.size();i++){
      if(chmax(c,sansei[ind[i]])) p=i;
    }
    Go(p);
  }
}
